            @{ Path = '\Microsoft\Windows\InstallService\'; Name = 'ScanForUpdatesAsUser' },
            @{ Path = '\Microsoft\Windows\InstallService\'; Name = 'SmartRetry' }
        )
        foreach ($entry in $storeUpdateTasks) {
